// ── Feedback learning cache ───────────────────────────────────────────────────
// Keyed by a stable "issue signature" (issueLabel + cssRule, URL-encoded).
// Structure: { [sig]: { correct: N, false_positive: N } }
// Loaded once at startup and written on every thumbs vote.
// Used by renderIssueWithWhere() to show adjusted confidence badges.
let _feedbackCache = {};
chrome.storage.local.get("klvFeedbackData", s => {
  _feedbackCache = s.klvFeedbackData || {};
});

// Build the signature used to key feedback data — same logic used in renderIssueWithWhere
function makeFeedbackSig(issueLabel, cssRule) {
  return encodeURIComponent((issueLabel || "") + "||" + (cssRule || ""));
}

