async function runInspection() {
  inspectBtn.disabled = true;
  inspectBtn.textContent = "Scanning…";

  content.innerHTML = `
    <div class="loading-state">
      <div class="spinner"></div>
      <span>Scanning Klaviyo components…</span>
    </div>`;

  try {
    const [tab] = await chrome.tabs.query({ active: true, currentWindow: true });

    try {
      await chrome.scripting.executeScript({ target: { tabId: tab.id }, files: ["content.js"] });
    } catch (_) {}

    let response = await chrome.tabs.sendMessage(tab.id, { action: "inspect" });

    if (!response || !response.success) {
      showError(response?.error || "Unknown error from content script.");
      return;
    }

    // ── Auto-retry if Klaviyo is present but 0 forms found ────────────────
    // Klaviyo injects form HTML asynchronously after the SDK loads.
    // If the scan runs before that's complete, findKlaviyoComponents() returns
    // empty and no Preview Fix buttons are shown. Detect this case and retry
    // once after 1.5s so the user doesn't have to manually click Scan Page again.
    if (response.data.formsFound === 0 && response.data.scriptHealth?.scripts?.length > 0) {
      content.innerHTML = `
        <div class="loading-state">
          <div class="spinner"></div>
          <span>Klaviyo detected — waiting for forms to load…</span>
        </div>`;
      await new Promise(r => setTimeout(r, 1500));
      const retry = await chrome.tabs.sendMessage(tab.id, { action: "inspect" }).catch(() => null);
      if (retry?.success) response = retry;
    }

    // ── MAIN world enrichment pass ────────────────────────────────────────
    // Run a single MAIN-world script that collects everything that needs
    // access to page globals: CMP globals, API errors, form targeting, geo data.
    let mainWorld = {};
    try {
      const mwResult = await chrome.scripting.executeScript({
        target: { tabId: tab.id },
        world: "MAIN",
        func: () => {
          // CMP global detection
          const cmpGlobals = [
            { name: "OneTrust",       global: "OneTrust" },
            { name: "Cookiebot",      global: "Cookiebot" },
            { name: "TrustArc",       global: "truste" },
            { name: "Usercentrics",   global: "UC_UI" },
            { name: "CookieYes",      global: "cookieyes" },
            { name: "Klaro",          global: "klaro" },
            { name: "Didomi",         global: "Didomi" },
            { name: "Quantcast CMP",  global: "QuantcastChoiceApi" },
          ];
          const detectedCmps = cmpGlobals.filter(c => !!window[c.global]).map(c => c.name);
          if (typeof window.__tcfapi === "function") detectedCmps.push("TCF v2 CMP");
          if (typeof window.__cmpapi  === "function") detectedCmps.push("CMP v1");

          // localStorage accessibility check
          let localStorageBlocked = false;
          try {
            localStorage.setItem("__klv_test", "1");
            localStorage.removeItem("__klv_test");
          } catch(_) { localStorageBlocked = true; }

          // API errors from Klaviyo's form fetch globals
          const apiErrors = ["_klvFormResp","_klvFormResp2","_klvFormResp3"]
            .map(k => window[k])
            .filter(v => typeof v === "string" && v.startsWith("error:"))
            .map(v => v.replace(/^error:\s*/, ""));

          // Form targeting from klaviyoOnsite localStorage
          let formTargeting = null;
          try {
            const raw = localStorage.getItem("klaviyoOnsite");
            if (raw) formTargeting = JSON.parse(raw);
          } catch(_) {}

          // Company ID from script tag — supports both new (?company_id=XXX) and
          // legacy (/onsite/js/XXX/klaviyo.js) URL formats.
          const loaderScript = Array.from(document.scripts).find(s => s.src && (
            s.src.includes("company_id=") ||
            /static\.klaviyo\.com\/onsite\/js\/[A-Za-z0-9]+\/klaviyo\.js/.test(s.src)
          ));
          const companyId = loaderScript ? (
            (loaderScript.src.match(/company_id=([^&]+)/) || [])[1] ||
            (loaderScript.src.match(/\/onsite\/js\/([A-Za-z0-9]+)\/klaviyo\.js/) || [])[1]
          ) : null;

          // ── jQuery version conflict detection ──────────────────────────────
          // Multiple jQuery versions on the same page can cause Klaviyo's
          // onsite scripts to reference the wrong version and silently fail.
          let jqueryConflict = null;
          try {
            const versions = new Set();
            if (window.jQuery && window.jQuery.fn) versions.add(window.jQuery.fn.jquery);
            if (window.$ && window.$.fn && window.$.fn.jquery !== window.jQuery?.fn?.jquery) {
              versions.add(window.$.fn.jquery);
            }
            // Check for legacy namespaced versions (jQuery1x, jQuery2x etc.)
            Object.keys(window).filter(k => /^jQuery\d/.test(k)).forEach(k => {
              try { if (window[k]?.fn?.jquery) versions.add(window[k].fn.jquery); } catch(_) {}
            });
            if (versions.size > 1) {
              jqueryConflict = { versions: Array.from(versions) };
            }
          } catch(_) {}

          // ── window.klaviyo shape check ─────────────────────────────────────
          // After page load, window.klaviyo should be Klaviyo's command queue
          // (an object/array with a push method). If it's missing or has been
          // replaced with something else, forms will silently fail to receive
          // any openForm / identify calls the page might send.
          let klaviyoOverride = null;
          try {
            const klv = window.klaviyo;
            if (loaderScript && typeof klv !== "undefined") {
              const hasPush = typeof klv.push === "function";
              const isPlainArray = Array.isArray(klv) && !hasPush;
              const isNull = klv === null;
              if (isPlainArray || isNull || typeof klv === "string" || typeof klv === "number") {
                klaviyoOverride = { type: typeof klv, isArray: Array.isArray(klv) };
              }
            }
          } catch(_) {}

          return { detectedCmps, localStorageBlocked, apiErrors, formTargeting, companyId, jqueryConflict, klaviyoOverride };
        },
      });
      mainWorld = mwResult?.[0]?.result || {};
    } catch(_) {}

    // ── Geo-IP fetch (via background, bypasses CORS) ──────────────────────
    let geoData = null;
    if (mainWorld.companyId) {
      try {
        geoData = await chrome.runtime.sendMessage({
          action: "fetchGeoIp",
          companyId: mainWorld.companyId,
        });
      } catch(_) {}
    }

    // ── Inject enrichment into response data ──────────────────────────────
    // Merge MAIN world CMP detections with DOM-based ones from content script
    if (mainWorld.detectedCmps?.length) {
      const existing = response.data.cmp?.detected || [];
      const merged = [...new Set([...existing, ...mainWorld.detectedCmps])];
      response.data.cmp = { ...(response.data.cmp || {}), detected: merged };
    }
    if (mainWorld.localStorageBlocked) {
      response.data.scriptHealth.issues.unshift({
        severity: "critical", code: "LOCALSTORAGE_BLOCKED",
        title: "localStorage is blocked",
        detail: "The extension could not read or write localStorage on this page. This typically means a browser privacy extension, strict cookie settings, or a CMP has blocked storage access. Klaviyo uses localStorage to manage form display frequency, identity, and A/B test assignments — blocking it causes forms to malfunction.",
        fix: "Check browser cookie settings and any active privacy/ad-blocking extensions. If a CMP is present, ensure it grants localStorage access before Klaviyo initialises.",
      });
    }

    // ── jQuery version conflict (from MAIN world) ─────────────────────────
    if (mainWorld.jqueryConflict) {
      const vs = mainWorld.jqueryConflict.versions.join(" vs ");
      response.data.scriptHealth.issues.push({
        severity: "warning",
        code: "JQUERY_VERSION_MISMATCH",
        title: `Multiple jQuery versions detected (${vs})`,
        detail: `The page has loaded ${mainWorld.jqueryConflict.versions.length} different jQuery versions: ${vs}. When multiple versions conflict, Klaviyo's form scripts may reference the wrong version, causing validation or event handlers to fail silently. This often happens when a theme ships its own jQuery that differs from a page builder or plugin jQuery.`,
        fix: "Identify which scripts are loading each jQuery version and consolidate to a single version. Use your browser's Network tab to find all jquery.js requests. If one version is required by a legacy plugin, consider using jQuery.noConflict() carefully or replacing the legacy plugin.",
      });
    }

    // ── window.klaviyo shape unexpected (from MAIN world) ────────────────
    if (mainWorld.klaviyoOverride) {
      response.data.scriptHealth.issues.unshift({
        severity: "critical",
        code: "KLAVIYO_WINDOW_OVERRIDE",
        title: "window.klaviyo has been overridden",
        detail: `The window.klaviyo global exists but is not a valid Klaviyo SDK object (found: ${mainWorld.klaviyoOverride.isArray ? "plain array" : mainWorld.klaviyoOverride.type}). This means another script has clobbered the Klaviyo push queue after (or instead of) the SDK initialising. Any klaviyo.push() or openForm() calls on this page will fail silently.`,
        fix: "Search the page's scripts for any code that assigns window.klaviyo = … and remove it. Use the browser console to check: console.log(typeof window.klaviyo, window.klaviyo.push) — it should be an object with a function push method.",
      });
    }
    if (geoData?.ok && geoData.data) {
      response.data.geoData = geoData.data;
    }
    if (mainWorld.formTargeting) {
      response.data.formTargeting = mainWorld.formTargeting;
    }

    // ── Check Klaviyo's own API response globals (runs in MAIN world) ──
    // Klaviyo writes _klvFormResp/_klvFormResp2/_klvFormResp3 with the result
    // of its form-fetch calls. If these contain errors (e.g. 503 from a.klaviyo.com),
    // surface it as a top-level critical issue — no CSS fix can help.
    try {
      const apiCheck = await chrome.scripting.executeScript({
        target: { tabId: tab.id },
        world: "MAIN",
        func: () => {
          const respGlobals = ["_klvFormResp", "_klvFormResp2", "_klvFormResp3"];
          return respGlobals
            .map(k => window[k])
            .filter(v => typeof v === "string" && v.startsWith("error:"))
            .map(v => v.replace(/^error:\s*/, ""));
        },
      });
      const apiErrors = apiCheck?.[0]?.result || [];
      if (apiErrors.length > 0) {
        const errMsg = apiErrors[0];
        const is503 = errMsg.toLowerCase().includes("failed to fetch") || errMsg.includes("503");
        response.data.scriptHealth.issues.unshift({
          severity: "critical",
          code: "API_FETCH_ERROR",
          title: "Klaviyo API error — form data could not load",
          detail: `Klaviyo tried to fetch signup form data from its servers (a.klaviyo.com) but received: "${errMsg}". ${is503 ? "This is typically a 503 Service Unavailable — Klaviyo's backend is not serving form data for this account. " : ""}No CSS or JS tweak can make forms appear when the form definition was never delivered to the browser.`,
          fix: "Check status.klaviyo.com for ongoing incidents. Verify the Klaviyo account is active and not suspended. Confirm the company_id in the script tag is correct. If the error persists after a page reload, escalate to Klaviyo Support.",
        });
      }
    } catch (_) { /* MAIN world access may fail on restricted pages — safe to ignore */ }

    render(response.data);
    // Persist full results so they survive popup close/reopen on the same page.
    // cardStates is reset to {} on each fresh scan so stale collapse state doesn't carry over.
    await chrome.storage.local.set({ klvLastScan: { url: tab.url, data: response.data, ts: Date.now(), cardStates: {} } });
    saveToHistory(response.data);
  } catch (err) {
    showError(err.message || "Could not communicate with the page. Try reloading the tab.");
  } finally {
    inspectBtn.disabled = false;
    inspectBtn.textContent = "Scan Page";
  }
}

// ── PICK RESULT VIEW ─────────────────────────────────────

function renderPickResult(result) {
  // If the user picked a recognised Klaviyo component, show the same
  // full-depth output as Scan Page does for that one component.
  if (result.mode === "pick-component" && result.form) {
    renderPickComponent(result);
    return;
  }

  // Generic element pick — simple CSS visibility check view
  const { element, issues, inlineStyles, totalIssues } = result;
  const hasIssues = totalIssues > 0 || (inlineStyles && inlineStyles.length > 0);

  let html = pickBackBar("Element Inspector");

  html += `<div class="pick-element-chip">
    <span class="pick-chip-label">Inspected</span>
    <code class="pick-chip-tag">${escHtml(element)}</code>
  </div>`;

  if (!hasIssues) {
    html += `<div class="pick-ok-msg">✅ No CSS visibility issues detected on this element.</div>`;
  } else {
    if (issues && issues.length > 0) {
      html += `<div class="issue-section"><div class="issue-section-title">CSS Issues</div>${renderIssues(issues)}</div>`;
    }
    if (inlineStyles && inlineStyles.length > 0) {
      html += renderInlineStyles(inlineStyles, "Inline styles on element:");
    }
  }

  const pickTarget = pickResultArea || content;
  pickTarget.style.display = '';
  pickTarget.innerHTML = html;
  if (pickPanelActions) pickPanelActions.style.display = 'none';
  attachFeedbackListeners();
  attachPickBarListeners();
}

// ── Full component view for picked Klaviyo components ────
// Renders the same form card as Scan Page but scoped to the one picked element.

function renderPickComponent(result) {
  const { form, url } = result;
  const siteUrl = url || "";

  _scanContext = { siteUrl };

  const issueWord  = form.totalIssues === 1 ? "issue" : "issues";
  const dotClass   = form.totalIssues === 0 ? "dot-ok" : form.totalIssues >= 3 ? "dot-fail" : "dot-warn";
  const badgeClass = form.totalIssues === 0 ? "badge-ok" : form.totalIssues < 3 ? "badge-warn" : "badge-fail";
  const badgeLabel = form.totalIssues === 0 ? "✓ No issues" : `${form.totalIssues} ${issueWord} found`;

  let html = pickBackBar("Component Inspection");

  // Compact summary badge
  html += `<div class="summary-bar">
    <div class="summary-left">
      <span class="badge ${badgeClass}">${badgeLabel}</span>
      <span class="summary-meta">${escHtml(form.componentType || "Component")}</span>
    </div>
    <span class="summary-meta pick-url-label" title="${escHtml(siteUrl)}">${escHtml(siteUrl ? (() => { try { return new URL(siteUrl).hostname; } catch(_){return siteUrl;} })() : "")}</span>
  </div>`;

  // ── Form card — same rendering as Scan Page ──
  const formLabel = form.formId
    ? `<span class="form-type-text">${escHtml(form.componentType || "Component")}:</span>
       <span class="form-id-link" data-form-id="${escHtml(form.formId)}" title="Open in Klaviyo dashboard">
         <span class="form-name-id">${escHtml(form.formId)}</span>
         <svg class="form-id-arrow" width="10" height="10" viewBox="0 0 24 24" fill="none">
           <path d="M7 17L17 7M17 7H7M17 7v10" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/>
         </svg>
       </span>`
    : `<span class="form-type-text">${escHtml(form.componentType || "Component")}</span>`;

  html += `<div class="forms-list"><details class="form-card" open data-card-idx="0">
    <summary class="form-card-header">
      <div class="form-label">
        <span class="status-dot ${dotClass}"></span>
        ${formLabel}
        ${form.totalIssues > 0 ? `<span class="issue-count-badge">${form.totalIssues} ${issueWord}</span>` : ""}
      </div>
      <div class="form-header-right">
        <span class="card-chevron">▾</span>
      </div>
    </summary>
    <div class="form-card-body">`;

  // Deduplicate issues (same logic as main render)
  const rawIssues = [
    ...form.containerIssues.map(i => ({ ...i, _where: null })),
    ...(form.buttonResults || []).flatMap(b => b.issues.map(i => ({ ...i, _where: b.element }))),
    ...(form.inputResults  || []).flatMap(r => r.issues.map(i => ({ ...i, _where: r.element }))),
  ];
  const deduped = [];
  rawIssues.forEach(issue => {
    const srcKey = (issue.sources && issue.sources[0])
      ? `${issue.sources[0].source}|${issue.sources[0].selector}|${issue.sources[0].value}`
      : "__no-src__";
    const key = `${issue.label}||${srcKey}`;
    const existing = deduped.find(d => d._key === key);
    if (existing) {
      if (issue._where && !existing._wheres.includes(issue._where)) existing._wheres.push(issue._where);
    } else {
      deduped.push({ ...issue, _key: key, _wheres: issue._where ? [issue._where] : [] });
    }
  });

  const allInline = [
    ...(form.containerInline || []).map(s => ({ ...s, _where: "container" })),
    ...(form.buttonResults   || []).flatMap(b => b.inlineStyle.map(s => ({ ...s, _where: b.element }))),
  ];

  if (form.totalIssues === 0 && allInline.length === 0) {
    html += `<div class="pick-ok-msg">✅ No CSS conflicts detected on this component.</div>`;
  }

  if (deduped.length > 0) {
    html += `<div class="issue-section">`;
    deduped.forEach(issue => {
      const whereTag = issue._wheres.length > 0
        ? `<div class="issue-where">also affects ${issue._wheres.map(w => `<code>${escHtml(w)}</code>`).join(", ")}</div>`
        : "";
      html += renderIssueWithWhere(issue, whereTag, { siteUrl, componentType: form.componentType, formId: form.formId });
    });
    html += `</div>`;
  }
  if (allInline.length > 0) html += renderInlineStyles(allInline, "Inline styles detected:");
  if (form.zIndexStack && form.zIndexStack.length > 0) html += renderZIndexMap(form.zIndexStack);
  html += renderCustomerMessage(form, 0);

  // ── Test Submit row (pick mode) ──────────────────────────
  // Shown whenever the picked element has a resolvable formId so the
  // agent can immediately run a test subscription without leaving the view.
  if (form.formId) {
    html += `
    <div class="pick-test-row" style="padding:10px 12px 6px;display:flex;align-items:center;gap:8px;border-top:1px solid var(--border,#e2e8f0)">
      <button class="btn-test-submit" data-form-id="${escHtml(form.formId)}"
        style="background:#f0fdf4;border:1.5px solid #86efac;color:#15803d;border-radius:6px;padding:5px 12px;font-size:12px;cursor:pointer;font-family:inherit;font-weight:500;">
        📧 Test Submit
      </button>
      <span style="font-size:11px;color:var(--text-muted,#6b7280)">Test a subscription through this form</span>
    </div>
    <div class="scanner-form-result" id="scanner-result-${escHtml(form.formId)}" style="padding:0 12px"></div>`;
  }

  html += `</div></details></div>`;

  const pickTarget2 = pickResultArea || content;
  pickTarget2.style.display = '';
  pickTarget2.innerHTML = html;
  if (pickPanelActions) pickPanelActions.style.display = 'none';
  attachFeedbackListeners();
  applyAndTrackCardStates("klvPickResult");
  attachPickBarListeners();

  // Form ID chip → open dashboard
  document.querySelectorAll(".form-id-link").forEach(chip => {
    chip.addEventListener("click", e => {
      e.preventDefault(); e.stopPropagation();
      const fid = chip.dataset.formId;
      if (fid) chrome.tabs.create({ url: `https://www.klaviyo.com/forms/${fid}` });
    });
  });

  // Preview Fix toggle
  document.querySelectorAll(".btn-preview-fix").forEach(btn => {
    btn.addEventListener("click", () => togglePreviewFix(btn));
  });

  // Find Source toggle
  document.querySelectorAll(".btn-find-source").forEach(btn => {
    btn.addEventListener("click", () => findSource(btn));
  });

  // Restore active fix button states on popup reopen
  restoreFixButtonStates();

  // Dismiss listeners
  attachDismissListeners();
  applyDismissed();

  // Copy message
  document.querySelectorAll(".btn-copy-msg").forEach(btn => {
    btn.dataset.plain = buildCustomerMessage(form) || "";
    btn.addEventListener("click", () => {
      const text = btn.dataset.plain || "";
      navigator.clipboard.writeText(text).catch(() => {
        const ta = document.createElement("textarea");
        ta.value = text; ta.style.position = "fixed"; ta.style.opacity = "0";
        document.body.appendChild(ta); ta.select(); document.execCommand("copy"); document.body.removeChild(ta);
      });
      btn.classList.add("copied");
      btn.textContent = "✓ Copied!";
      setTimeout(() => { btn.classList.remove("copied"); btn.innerHTML = copyIcon() + " Copy"; }, 2000);
    });
  });
}

// ── Shared back bar HTML ──────────────────────────────────
function pickBackBar(label) {
  return `<div class="pick-back-bar">
    <button class="btn-back" id="btn-dismiss-pick" title="Dismiss">✕ Dismiss</button>
    <span class="pick-back-label">${escHtml(label)}</span>
    <button class="btn-pick-again" id="btn-pick-again">
      <svg width="11" height="11" viewBox="0 0 24 24" fill="none">
        <path d="M4 4l7.5 18 3-7 7-3L4 4z" stroke="currentColor" stroke-width="2" stroke-linejoin="round"/>
        <path d="M14.5 14.5L20 20" stroke="currentColor" stroke-width="2" stroke-linecap="round"/>
      </svg>
      Pick another
    </button>
  </div>`;
}

// ── Shared pick bar event listeners ──────────────────────
function attachPickBarListeners() {
  document.getElementById("btn-dismiss-pick")?.addEventListener("click", () => {
    chrome.storage.local.remove("klvPickResult");
    setPickBtnActive(false);
    // Hide result area, restore idle actions
    if (pickResultArea) { pickResultArea.innerHTML = ''; pickResultArea.style.display = 'none'; }
    if (pickPanelActions) pickPanelActions.style.display = '';
  });

  document.getElementById("btn-pick-again")?.addEventListener("click", async () => {
    chrome.storage.local.set({ klvPickMode: true, klvPickResult: null });
    setPickBtnActive(true);
    showPickHint();
    try {
      const [tab] = await chrome.tabs.query({ active: true, currentWindow: true });
      try { await chrome.scripting.executeScript({ target: { tabId: tab.id }, files: ["content.js"] }); } catch (_) {}
      await chrome.tabs.sendMessage(tab.id, { action: "startPick" });
    } catch (err) { console.warn(err); }
    // Side panel stays open — no need to close.
  });
}

// ── MAIN RENDER ───────────────────────────────────────────

function render(data) {
  const { url, scriptHealth, behaviourIssues, formsFound, forms, totalIssues, csp, cmp, geoData, formTargeting } = data;
  _scanContext = { siteUrl: url };
  let html = "";

  const domain = (() => { try { return new URL(url).hostname; } catch (_) { return url; } })();

  // Count all issues including script/behaviour/csp
  const scriptIssueCount   = (scriptHealth?.issues || []).length;
  const behaviourIssueCount = (behaviourIssues || []).length;
  const cspIssueCount      = (csp?.issues || []).filter(i => i.severity !== "info").length;
  const allIssues = totalIssues + scriptIssueCount + behaviourIssueCount + cspIssueCount;

  const badgeClass = allIssues === 0 ? "badge-ok" : allIssues < 3 ? "badge-warn" : "badge-fail";
  const badgeLabel = allIssues === 0 ? "✓ No issues" : `${allIssues} issue${allIssues !== 1 ? "s" : ""} found`;

  html += `<div class="summary-bar">
    <div class="summary-left">
      <span class="badge ${badgeClass}">${badgeLabel}</span>
      <span class="summary-meta">${formsFound} component${formsFound !== 1 ? "s" : ""}</span>
    </div>
    <div style="display:flex;align-items:center;gap:6px;flex-shrink:0">
      <span class="summary-meta">${escHtml(domain)}</span>
      <button class="btn-copy-report" id="btn-copy-report" title="Copy full diagnostic report to clipboard">📋 Copy Report</button>
      <button class="btn-export-json" id="btn-export-json" title="Download scan results as CSV">⬇ Export</button>
    </div>
  </div>`;

  // ── Geo-targeting notice ──
  if (geoData) {
    const country = geoData.country_name || geoData.country || geoData.location?.country || "";
    const countryCode = geoData.country_code || geoData.country_iso_code || "";
    if (country || countryCode) {
      html += `<div class="geo-bar">
        🌍 Scanning from <strong>${escHtml(country || countryCode)}</strong>${countryCode && country ? ` (${escHtml(countryCode)})` : ""} — if the form has geo-targeting rules, they apply to this location.
      </div>`;
    }
  }

  // ── CMP warning ──
  const detectedCmps = cmp?.detected || [];
  if (detectedCmps.length > 0) {
    html += `<div class="cmp-bar">
      <span class="cmp-bar-icon">🍪</span>
      <div>
        <strong>Consent platform detected: ${escHtml(detectedCmps.join(", "))}</strong><br>
        <span class="cmp-bar-detail">This CMP may delay or block Klaviyo's localStorage access until the visitor accepts cookies. If forms aren't showing, check that the CMP grants consent before Klaviyo initialises, and that it doesn't block localStorage.</span>
      </div>
    </div>`;
  }

  // ── Form targeting summary ──
  if (formTargeting) {
    const targetingHtml = renderFormTargeting(formTargeting);
    if (targetingHtml) html += targetingHtml;
  }

  // ── CSP issues ──
  if (csp?.issues?.length > 0) {
    html += `<div class="section-block">
      <div class="section-block-header ${csp.issues[0].severity === "critical" ? "error" : "warning"}">
        <span class="section-icon">🔒</span>
        <div>
          <div class="section-title">Content Security Policy</div>
          <div class="section-sub">${csp.issues.length} CSP issue${csp.issues.length !== 1 ? "s" : ""} detected</div>
        </div>
      </div>`;
    csp.issues.forEach(i => { html += renderScriptIssue(i); });
    html += `</div>`;
  }

  // ── Script health panel ──
  html += renderScriptHealth(scriptHealth);

  // ── HAR file suggestion card (always shown) ──────────────
  html += `<div class="har-suggest-card" id="har-suggest-card">
    <div class="har-suggest-text">
      <span class="har-suggest-title">Can't reproduce the issue?</span>
      <span class="har-suggest-body">The customer's HAR file shows failed requests and timing issues a scan can't catch.</span>
    </div>
    <button class="har-suggest-btn" id="har-suggest-open">Request HAR File</button>
  </div>`;

  // ── Component cards ──
  if (formsFound === 0) {
    html += `<div class="no-forms">
      <div class="no-forms-title">No Klaviyo components found</div>
      <div class="no-forms-body">
        No signup forms, review widgets, or customer agent components were detected on this page.
        If you expect one to be here, it may be hidden inside an iframe, loaded after a delay,
        or triggered by user interaction (e.g. scroll or click).
      </div>
    </div>`;
    content.innerHTML = html;
    return;
  }

  // Separate healthy vs broken components
  const brokenForms  = forms.filter(f => !f.healthy);
  const healthyForms = forms.filter(f =>  f.healthy);

  // ── Healthy components — collapsed summary ──
  if (healthyForms.length > 0) {
    const summaryId = "healthy-summary";
    html += `<details class="healthy-summary" id="${summaryId}">
      <summary class="healthy-summary-toggle">
        <span class="healthy-check">✅</span>
        <span class="healthy-toggle-text">
          ${healthyForms.length} component${healthyForms.length !== 1 ? "s" : ""} — no CSS conflicts detected
        </span>
        <span class="healthy-chevron">▸</span>
      </summary>
      <div class="healthy-list">`;
    healthyForms.forEach(form => {
      const idChip = form.formId
        ? `<span class="form-id-link healthy-id-link" data-form-id="${escHtml(form.formId)}" title="Open form in Klaviyo dashboard">
            <span class="form-name-id">${escHtml(form.formId)}</span>
            <svg class="form-id-arrow" width="10" height="10" viewBox="0 0 24 24" fill="none"><path d="M7 17L17 7M17 7H7M17 7v10" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/></svg>
           </span>`
        : `<span class="healthy-item-tag">${escHtml(form.element)}</span>`;
      html += `<div class="healthy-item">
        <span class="status-dot dot-ok"></span>
        <span class="healthy-item-type">${escHtml(form.componentType || "Component")}</span>
        ${idChip}
      </div>`;
    });
    html += `</div></details>`;
  }

  // ── Broken components — expanded with full details ──
  if (brokenForms.length === 0 && healthyForms.length > 0) {
    // All components are healthy — nothing more to show
    html += `<div class="all-ok-msg">No CSS conflicts or script issues were found on this page.</div>`;
  }

  if (brokenForms.length > 0) {
    html += `<div class="forms-list">`;
    brokenForms.forEach((form, idx) => {
      const globalIdx = forms.indexOf(form);
      const cardId = `card-body-${globalIdx}`;
      const issueWord = form.totalIssues === 1 ? "issue" : "issues";
      const dotClass = form.totalIssues >= 3 ? "dot-fail" : "dot-warn";

      // Entire card is a <details> — click header to collapse/expand
      const formLabel = form.formId
        ? `<span class="form-type-text">${escHtml(form.componentType || "Component")}:</span><span class="form-id-link" data-form-id="${escHtml(form.formId)}" title="Open form in Klaviyo dashboard"><span class="form-name-id">${escHtml(form.formId)}</span><svg class="form-id-arrow" width="10" height="10" viewBox="0 0 24 24" fill="none"><path d="M7 17L17 7M17 7H7M17 7v10" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/></svg></span>`
        : `<span class="form-type-text">${escHtml(form.componentType || "Component")} ${form.index}</span>`;

      const cardDismissKey = `card||${escHtml(form.formId || (form.componentType + ":" + globalIdx))}`;
      html += `<details class="form-card" open data-card-idx="${globalIdx}" data-card-dismiss-key="${cardDismissKey}">
        <summary class="form-card-header">
          <div class="form-label">
            <span class="status-dot ${dotClass}"></span>
            ${formLabel}
            <span class="issue-count-badge">${form.totalIssues} ${issueWord}</span>
          </div>
          <div class="form-header-right">
            <button class="btn-dismiss-card" data-card-dismiss-key="${cardDismissKey}" title="Hide this component from view (reappears on next scan)">✕</button>
            <span class="card-chevron">▾</span>
          </div>
        </summary>
        <div class="form-card-body">`;

      // ── Collect all issues then deduplicate ──
      const rawIssues = [
        ...form.containerIssues.map(i => ({ ...i, _where: null })),
        ...(form.buttonResults || []).flatMap(b => b.issues.map(i => ({ ...i, _where: b.element }))),
        ...(form.inputResults  || []).flatMap(r => r.issues.map(i => ({ ...i, _where: r.element }))),
      ];

      // Deduplicate: same label + same CSS rule = one entry, locations merged
      const deduped = [];
      rawIssues.forEach(issue => {
        const srcKey = (issue.sources && issue.sources[0])
          ? `${issue.sources[0].source}|${issue.sources[0].selector}|${issue.sources[0].value}`
          : "__no-src__";
        const key = `${issue.label}||${srcKey}`;
        const existing = deduped.find(d => d._key === key);
        if (existing) {
          // Same rule already listed — just add the location if it's new
          if (issue._where && !existing._wheres.includes(issue._where)) {
            existing._wheres.push(issue._where);
          }
        } else {
          deduped.push({
            ...issue,
            _key: key,
            _wheres: issue._where ? [issue._where] : [],
          });
        }
      });

      const allInline = [
        ...(form.containerInline || []).map(s => ({ ...s, _where: "container" })),
        ...(form.buttonResults || []).flatMap(b => b.inlineStyle.map(s => ({ ...s, _where: b.element }))),
      ];

      if (deduped.length > 0) {
        html += `<div class="issue-section">`;
        deduped.forEach(issue => {
          let whereTag = "";
          if (issue._wheres.length > 0) {
            const labels = issue._wheres.map(w => `<code>${escHtml(w)}</code>`).join(", ");
            whereTag = `<div class="issue-where">also affects ${labels}</div>`;
          }
          html += renderIssueWithWhere(issue, whereTag, { siteUrl: url, componentType: form.componentType, formId: form.formId });
        });
        html += `</div>`;
      }
      if (allInline.length > 0) {
        html += renderInlineStyles(allInline, "Inline styles detected:");
      }

      // Z-index map
      if (form.zIndexStack && form.zIndexStack.length > 0) {
        html += renderZIndexMap(form.zIndexStack);
      }

      // Customer message box
      html += renderCustomerMessage(form, globalIdx);

      html += `</div></details>`;
    });
    html += `</div>`;
  }

  content.innerHTML = html;
  attachFeedbackListeners();
  applyAndTrackCardStates("klvLastScan");

  // ── HAR suggest button → open HAR panel ──
  document.getElementById("har-suggest-open")?.addEventListener("click", () => {
    document.getElementById("nav-har")?.click();
  });

  // Clicking any Klaviyo form ID chip (broken or healthy) opens the dashboard.
  document.querySelectorAll(".form-id-link").forEach(chip => {
    chip.addEventListener("click", (e) => {
      e.preventDefault();
      e.stopPropagation();
      const fid = chip.dataset.formId;
      if (fid) chrome.tabs.create({ url: `https://www.klaviyo.com/forms/${fid}` });
    });
  });

  // Preview Fix toggle buttons
  document.querySelectorAll(".btn-preview-fix").forEach(btn => {
    btn.addEventListener("click", () => togglePreviewFix(btn));
  });

  // Find Source buttons
  document.querySelectorAll(".btn-find-source").forEach(btn => {
    btn.addEventListener("click", () => findSource(btn));
  });

  // Attach plain-text to copy buttons
  document.querySelectorAll(".btn-copy-msg").forEach(btn => {
    const formIdx = parseInt(btn.dataset.formIdx, 10);
    const form = data.forms[formIdx]; // globalIdx preserved
    if (form) btn.dataset.plain = buildCustomerMessage(form) || "";
    btn.addEventListener("click", () => {
      const text = btn.dataset.plain || "";
      navigator.clipboard.writeText(text).catch(() => {
        const ta = document.createElement("textarea");
        ta.value = text; ta.style.position = "fixed"; ta.style.opacity = "0";
        document.body.appendChild(ta); ta.select(); document.execCommand("copy"); document.body.removeChild(ta);
      });
      btn.classList.add("copied");
      btn.textContent = "✓ Copied!";
      setTimeout(() => {
        btn.classList.remove("copied");
        btn.innerHTML = copyIcon() + " Copy";
      }, 2000);
    });
  });

  // Restore any active preview fixes so buttons show "↩ Restore" correctly
  // when the popup is reopened after a fix was applied (Bug 2 fix).
  restoreFixButtonStates();

  // Attach dismiss listeners and hide any previously dismissed warnings.
  attachDismissListeners();
  applyDismissed();

}

// ── SCRIPT HEALTH PANEL ───────────────────────────────────

function renderScriptHealth(sh) {
  if (!sh) return "";

  const issues = sh.issues || [];
  const scripts = sh.scripts || [];
  const ok = issues.length === 0 && scripts.length > 0;

  let html = `<div class="section-block">
    <div class="section-block-header ${ok ? "ok" : issues.some(i=>i.severity==="critical") ? "critical" : "warning"}">
      <span class="section-icon">⚙</span>
      <div>
        <div class="section-title">Klaviyo Script Health</div>
        <div class="section-sub">${scripts.length === 0 ? "No script detected" : `${scripts.length} script${scripts.length>1?"s":""} found${ok?" — all clear":""}`}</div>
      </div>
    </div>`;

  // Script rows
  if (scripts.length > 0) {
    html += `<div class="script-rows">`;
    scripts.forEach(s => {
      const typeOk = s.typeOk;
      html += `<div class="script-row">
        <div class="script-row-top">
          <span class="script-dot ${typeOk && s.inHead ? "dot-ok" : "dot-warn"}"></span>
          <span class="script-src">${escHtml(s.src.replace("https://","").replace("//",""))}</span>
        </div>
        <div class="script-row-meta">
          <span class="script-badge ${typeOk ? "sb-ok" : "sb-fail"}">type: ${escHtml(s.type)}</span>
          <span class="script-badge ${s.inHead ? "sb-ok" : "sb-warn"}">
            ${s.inHead ? "✓ in &lt;head&gt;" : "⚠ not in &lt;head&gt;"}
          </span>
          ${s.companyId ? `<span class="script-badge sb-info">id: ${escHtml(s.companyId)}</span>` : ""}
        </div>
      </div>`;
    });
    html += `</div>`;
  }

  // Issue rows
  issues.forEach(issue => { html += renderScriptIssue(issue); });

  html += `</div>`;
  return html;
}

function renderScriptIssue(issue) {
  const sev = issue.severity;
  const icon = sev === "critical" ? "🔴" : sev === "warning" ? "🟡" : "🔵";
  return `<div class="script-issue ${sev}">
    <div class="script-issue-head">
      <span>${icon}</span>
      <strong>${escHtml(issue.title)}</strong>
    </div>
    <div class="script-issue-detail">${escHtml(issue.detail)}</div>
    ${issue.fix ? `<div class="script-issue-fix">
      <span class="fix-label">Fix:</span> ${escHtml(issue.fix)}
    </div>` : ""}
  </div>`;
}

// ── ISSUE RENDERS ─────────────────────────────────────────

// Confidence dots: filled/empty circles (e.g. ●●●●○)
function renderConfidence(score) {
  if (!score) return "";
  const dots = Array.from({ length: 5 }, (_, i) =>
    `<span class="conf-dot ${i < score ? "conf-dot-on" : "conf-dot-off"}">●</span>`
  ).join("");
  const label = score >= 5 ? "Very likely cause" : score >= 4 ? "Likely cause" : score >= 3 ? "Possible cause" : "Worth checking";
  return `<span class="conf-bar" title="Confidence ${score}/5 — ${label}">${dots}</span>`;
}

// Render a single issue with an optional "on <element>" sub-label.
// ctx = { siteUrl, componentType, formId } for feedback logging.
function renderIssueWithWhere(issue, whereTag, ctx = {}) {
  const fbId = ++_fbCtr;
  const firstSrc = (issue.sources || []).find(s => !s.crossOrigin);
  const cssRule = firstSrc
    ? `${firstSrc.selector} { ${issue.property}: ${firstSrc.value}${firstSrc.important ? " !important" : ""}; }`
    : "";
  _fbData[fbId] = {
    siteUrl:       ctx.siteUrl       || _scanContext.siteUrl || "",
    componentType: ctx.componentType || "",
    formId:        ctx.formId        || "",
    issueLabel:    issue.label       || "",
    cssRule,
    sourceFile:    firstSrc ? firstSrc.source : "",
  };

  // ── Feedback-adjusted confidence ─────────────────────────────────────────
  // If previous votes on this exact CSS rule show it's often a false positive,
  // lower the displayed confidence score. If it's consistently correct, raise it.
  // Clamp between 1 and 5 so the score stays in the valid range.
  let displayConfidence = issue.confidence || 0;
  if (displayConfidence) {
    const sig = makeFeedbackSig(issue.label, cssRule);
    const votes = _feedbackCache[sig];
    if (votes) {
      const total = (votes.correct || 0) + (votes.false_positive || 0);
      if (total >= 3) {
        // Enough data — adjust confidence based on false-positive rate
        const fpRate = (votes.false_positive || 0) / total;
        if (fpRate >= 0.7)      displayConfidence = Math.max(1, displayConfidence - 2);
        else if (fpRate >= 0.4) displayConfidence = Math.max(1, displayConfidence - 1);
        else if (fpRate <= 0.1) displayConfidence = Math.min(5, displayConfidence + 1);
      }
    }
  }
  const confidenceChanged = displayConfidence !== (issue.confidence || 0);
  const learnedTag = confidenceChanged
    ? `<span class="fb-learned-badge" title="Confidence adjusted based on ${(() => { const sig = makeFeedbackSig(issue.label, cssRule); const v = _feedbackCache[sig]; return v ? ((v.false_positive||0) + (v.correct||0)) : 0; })()} feedback votes">🎓 learned</span>`
    : "";

  const icon = issue.severity === "critical" ? "🔴" : "🟡";
  const fixBtn = issue.fixId
    ? `<button class="btn-preview-fix" data-fix-id="${issue.fixId}" data-fix-selector="${escHtml(issue.fixSelector || "")}" data-fix-property="${escHtml(issue.property || "")}" title="Temporarily apply fix on page to see if the form appears">👁 Preview Fix</button>`
    : "";

  // "Find Source" button — show for any CSS issue (has a property).
  // Prefer fixSelector; fall back to the first readable source's selector.
  const _fsSelector = issue.fixSelector
    || (issue.sources || []).find(s => !s.crossOrigin && s.selector)?.selector
    || "";
  const findSourceBtn = (issue.property && _fsSelector)
    ? `<button class="btn-find-source" data-fix-selector="${escHtml(_fsSelector)}" data-fix-property="${escHtml(issue.property || "")}" title="Disable stylesheets one by one to confirm which one is causing this conflict">🔍 Find Source</button>`
    : "";

  // Stable key for dismiss persistence (cleared on next Scan Page)
  const firstSrcForKey = (issue.sources || []).find(s => !s.crossOrigin);
  const dismissKey = encodeURIComponent(
    (issue.label || "") + "||" + (firstSrcForKey?.selector || "") + "||" + (firstSrcForKey?.value || "")
  );

  let html = `<div class="issue-item ${issue.severity}" data-dismiss-key="${dismissKey}">
    <div class="issue-header">
      <div class="issue-name-row">
        <span class="issue-label">
          <code>${escHtml(issue.label)}</code>
          ${issue.hasImportant ? `<span class="important-badge">!important</span>` : ""}
        </span>
        <button class="btn-dismiss-issue" data-dismiss-key="${dismissKey}" title="Hide this warning (reappears on next scan)">✕</button>
      </div>
      <div class="issue-meta-row">
        ${renderConfidence(displayConfidence)}${learnedTag}
        <div class="issue-btn-group">
          ${fixBtn}
          ${findSourceBtn}
        </div>
      </div>
    </div>`;

  if (issue.themeMatch) {
    html += `<div class="theme-badge-row">
      <span class="theme-badge">📦 ${escHtml(issue.themeMatch.theme)}</span>
      ${issue.themeMatch.note ? `<span class="theme-note">${escHtml(issue.themeMatch.note)}</span>` : ""}
    </div>`;
  }

  html += whereTag;

  if (issue.explain) {
    html += `<div class="issue-explain">${escHtml(issue.explain)}</div>`;
  }

  // ── DOM Breadcrumb — shows exactly where in the page this element lives ──
  if (issue.domPath) {
    html += `<div class="dom-breadcrumb">
      <span class="dom-breadcrumb-label">📍 Element path</span>
      <span class="dom-breadcrumb-path">${escHtml(issue.domPath)}</span>
      <button class="btn-copy-path" data-copy="${escHtml(issue.domPath)}" title="Copy path to clipboard">⧉ Copy</button>
    </div>`;
  }

  if (issue.sources && issue.sources.length > 0) {
    html += `<div class="css-sources"><div class="css-sources-label">📄 Caused by this CSS rule:</div>`;
    issue.sources.forEach(src => {
      if (src.crossOrigin) {
        const crossLabel = src.isShopifyKlaviyoApp
          ? ` — ⚠️ Klaviyo app CSS on Shopify CDN (can't inspect — CORS blocked)`
          : ` — cross-origin, can't read rules`;
        html += `<div class="css-source-row css-source-synthetic${src.isShopifyKlaviyoApp ? " css-source-klaviyo-app" : ""}">
          <span class="css-src-file css-src-cross-origin">${escHtml(src.source)}</span>
          <span class="css-src-cross">${crossLabel}</span>
          ${src.syntheticNote ? `<br><span class="css-src-synthetic-note">${escHtml(src.syntheticNote)}</span>` : ""}
        </div>`;
      } else {
        const spec = src.specificity
          ? `<span class="specificity-chip" title="CSS Specificity">(${src.specificity.a},${src.specificity.b},${src.specificity.c})</span>`
          : "";
        html += `<div class="css-source-row">
          <span class="css-src-file-label">File: </span><span class="css-src-file">${escHtml(src.source)}</span>${spec}<br>
          ${src.layerName ? `<span class="css-src-layer">@layer ${escHtml(src.layerName)}</span><br>` : ""}
          ${src.mediaQuery ? `<span class="css-src-media">@media ${escHtml(src.mediaQuery)}</span><br>` : ""}
          <span class="css-src-rule-label">Rule: </span><span class="css-src-selector">${escHtml(src.selector)}</span>
          <span style="color:#565f89"> { </span>
          <span class="css-src-prop">${escHtml(issue.property)}</span>
          <span style="color:#565f89">: </span>
          <span class="css-src-value">${escHtml(src.value)}</span>
          ${src.important ? `<span class="css-src-important"> !important</span>` : ""}
          <span style="color:#565f89"> }</span>
        </div>`;
      }
    });
    html += `</div>`;
  } else if (issue.property && !["dimensions","overflow"].includes(issue.property)) {
    html += `<div class="no-source-note">Could not trace to a specific rule — may be set via JavaScript or a cross-origin stylesheet.</div>`;
  }

  // ── Fix suggestion for button style override issues ────────────────────────
  if (issue.klaviyoIntended && issue.fixSuggestion) {
    html += `<div class="style-fix-suggestion">
      <div class="style-fix-header">💡 Fix — have the site developer add this to the website's CSS:</div>
      <code class="style-fix-code">${escHtml(issue.fixSuggestion)}</code>
    </div>`;
  }

  // ── Feedback row ──
  const fbRuleHtml = cssRule
    ? `<div class="fb-context">
        <span class="fb-context-label">Flagged rule:</span>
        <code class="fb-context-rule">${escHtml(cssRule)}</code>
        ${firstSrc && firstSrc.source ? `<span class="fb-context-file">${escHtml(firstSrc.source.replace(/^https?:\/\/[^/]+/, ""))}</span>` : ""}
      </div>`
    : `<div class="fb-context">
        <span class="fb-context-label">Flagged:</span>
        <code class="fb-context-rule">${escHtml(issue.label)}</code>
      </div>`;

  html += `<div class="feedback-row" id="fb-${fbId}" data-fb-id="${fbId}">
    ${fbRuleHtml}
    <div class="fb-actions">
      <span class="fb-question">Accurate?</span>
      <button class="fb-btn fb-yes" data-fb-id="${fbId}">👍 Yes</button>
      <button class="fb-btn fb-no"  data-fb-id="${fbId}">👎 No</button>
    </div>
  </div>`;

  html += `</div>`;
  return html;
}

// Used for pick-result issue lists (no form context)
function renderIssues(issues) {
  return issues.map(issue => renderIssueWithWhere(issue, "", {})).join("");
}

function renderInlineStyles(inlineStyles, title) {
  let html = `<div class="inline-style-block"><div class="inline-style-title">⚠ ${escHtml(title)}</div>`;
  inlineStyles.forEach(s => {
    html += `<div class="inline-style-row">style="${escHtml(s.property)}: ${escHtml(s.value)}${s.important ? " !important" : ""}"</div>`;
  });
  html += `</div>`;
  return html;
}

// ── CUSTOMER MESSAGE ──────────────────────────────────────
// Language based on Klaviyo internal KB + real agent ticket examples

const FIX_ADVICE = {
  "display":        { fix: sel => `${sel} { display: block !important; }`,       plain: "Remove or override the display:none rule. Your developer can add a more specific CSS rule to force the element to show." },
  "visibility":     { fix: sel => `${sel} { visibility: visible !important; }`,  plain: "Change visibility to visible. Your developer needs to override or remove this rule." },
  "opacity":        { fix: sel => `${sel} { opacity: 1 !important; }`,           plain: "Set opacity back to 1 so the element is no longer transparent." },
  "pointer-events": { fix: sel => `${sel} { pointer-events: auto !important; }`, plain: "Remove or change pointer-events to auto so buttons and links respond to clicks." },
  "max-height":     { fix: sel => `${sel} { max-height: none !important; }`,     plain: "Remove or increase the max-height value so the element's content is not clipped." },
  "overflow":       { fix: null,                                                   plain: "The parent container's overflow or height settings need to be adjusted so the Klaviyo component is not clipped." },
  "dimensions":     { fix: null,                                                   plain: "Check for width:0 or height:0 constraints on the element or one of its parent containers." },
};

// Group raw issues by their label, combining affected targets (container/button/input).
// This avoids listing "visibility: hidden" 11 times when it affects many elements.
function groupIssuesForMessage(form) {
  const raw = [
    ...form.containerIssues.map(i => ({ ...i, _ttype: "container" })),
    ...(form.buttonResults || []).flatMap(b => b.issues.map(i => ({ ...i, _ttype: "button" }))),
    ...(form.inputResults  || []).flatMap(r => r.issues.map(i => ({ ...i, _ttype: "input" }))),
  ];
  if (!raw.length) return [];

  // Group by label
  const map = new Map();
  raw.forEach(issue => {
    if (!map.has(issue.label)) {
      map.set(issue.label, { issue, counts: { container: 0, button: 0, input: 0 } });
    }
    map.get(issue.label).counts[issue._ttype]++;
  });

  return [...map.values()].map(({ issue, counts }) => {
    const parts = [];
    if (counts.container) parts.push("form container");
    if (counts.button)    parts.push(counts.button === 1 ? "submit button" : `submit button (×${counts.button})`);
    if (counts.input)     parts.push(counts.input  === 1 ? "input field"   : `input field (×${counts.input})`);
    return { ...issue, targetSummary: parts.join(", ") };
  });
}

function buildCustomerMessage(form) {
  const grouped = groupIssuesForMessage(form);
  if (!grouped.length) return null;

  const type  = form.componentType || "component";
  const lines = [];

  lines.push("Hi {{ticket.requester.first_name}},");
  lines.push("");
  lines.push("Thanks for reaching out. My name is {{current_user.first_name}}.");
  lines.push("");
  lines.push(`Support is limited when it comes to custom CSS/theme-level changes. From what I can see, the issue with your Klaviyo ${type} is being caused by CSS in your site's theme overriding the ${type}'s default styling. This is not coming from Klaviyo, so a developer or theme provider will need to adjust it.`);
  lines.push("");
  lines.push("Here's what's happening:");

  grouped.forEach((issue, idx) => {
    const src = (issue.sources || []).find(s => !s.crossOrigin);
    lines.push("");

    // Issue heading — label + explain in one line
    const explain = issue.explain ? ` ${issue.explain}` : "";
    lines.push(`Issue ${grouped.length > 1 ? `${idx + 1} — ` : "— "}${issue.label}${issue.hasImportant ? " (!important)" : ""}${explain}`);

    // Conflicting CSS block
    if (src) {
      const important = src.important ? " !important" : "";
      lines.push("");
      lines.push("Conflicting CSS:");
      lines.push("");
      lines.push("```");
      lines.push(`${src.selector} {`);
      lines.push(`  ${issue.property}: ${src.value}${important};`);
      lines.push(`}`);
      lines.push("```");
      lines.push("");
      lines.push(`Source: ${src.source}`);
    }
  });

  lines.push("");
  lines.push(`Once this CSS is adjusted or scoped properly, the ${type} should display correctly. If the issue continues after that, feel free to reply and we'll take another look.`);

  return lines.join("\n");
}

function renderCustomerMessage(form, formIdx) {
  const grouped = groupIssuesForMessage(form);
  if (!grouped.length) return "";

  const type  = escHtml(form.componentType || "component");
  const count = grouped.length;

  let body = `Hi {{ticket.requester.first_name}},\n\n`;
  body += `Thanks for reaching out. My name is {{current_user.first_name}}.\n\n`;
  body += `Support is limited when it comes to custom CSS/theme-level changes. From what I can see, the issue with your Klaviyo <strong>${type}</strong> is being caused by CSS in your site's theme overriding the ${type}'s default styling. This is not coming from Klaviyo, so a developer or theme provider will need to adjust it.\n\n`;
  body += `<strong>Here's what's happening:</strong>\n`;

  grouped.forEach((issue, idx) => {
    const src = (issue.sources || []).find(s => !s.crossOrigin);
    const explain = issue.explain ? ` ${escHtml(issue.explain)}` : "";

    body += `\n<hr class="msg-divider">`;
    body += `<span class="msg-section-label">Issue${count > 1 ? ` ${idx + 1}` : ""} — ${escHtml(issue.label)}${issue.hasImportant ? " <code>!important</code>" : ""}</span>`;
    body += `<span class="msg-issue-explain">${explain}</span>\n`;

    if (src) {
      const important = src.important ? " !important" : "";
      body += `\n<strong>Conflicting CSS:</strong>\n`;
      body += `<pre class="msg-code-block">${escHtml(src.selector)} {\n  ${escHtml(issue.property)}: ${escHtml(src.value)}${escHtml(important)};\n}</pre>`;
      body += `\n<span class="msg-source-line">Source: <code class="msg-file-badge">${escHtml(src.source)}</code></span>`;
    }
  });

  body += `\n<hr class="msg-divider">Once this CSS is adjusted or scoped properly, the ${type} should display correctly. If the issue continues after that, feel free to reply and we'll take another look.`;

  return `
    <div class="customer-msg-wrap">
      <div class="customer-msg-header">
        <div class="customer-msg-header-left">
          <div class="customer-msg-header-icon">✉</div>
          <div>
            <div class="customer-msg-title">Customer Message</div>
            <div class="customer-msg-sub">Ready to copy &amp; send</div>
          </div>
        </div>
        <button class="btn-copy-msg" data-form-idx="${formIdx}">
          ${copyIcon()} Copy
        </button>
      </div>
      <div class="customer-msg-body">${body}</div>
    </div>`;
}

// ── FORM TARGETING SUMMARY ───────────────────────────────
function renderFormTargeting(targeting) {
  const modal = targeting?.viewedForms?.modal;
  if (!modal) return "";

  const viewedForms   = modal.viewedForms   || {};
  const disabledForms = modal.disabledForms || {};
  const allFormIds    = [...new Set([...Object.keys(viewedForms), ...Object.keys(disabledForms)])];
  if (allFormIds.length === 0) return "";

  const fmtDate = (ts) => {
    if (!ts) return null;
    const d = new Date(ts < 1e10 ? ts * 1000 : ts); // handle seconds or ms
    const now = Date.now();
    const diff = Math.round((now - d.getTime()) / (1000 * 60 * 60 * 24));
    const time = d.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
    if (diff === 0) return `today at ${time}`;
    if (diff === 1) return `yesterday at ${time}`;
    return `${diff} days ago (${d.toLocaleDateString([], { month: "short", day: "numeric" })} at ${time})`;
  };

  let rows = "";
  allFormIds.forEach(id => {
    const variationId  = viewedForms[id]   || null;
    const closeInfo    = disabledForms[id]  || null;
    const lastCloseTs  = closeInfo?.lastCloseTime || null;
    const isSuppressed = !!lastCloseTs;

    rows += `<div class="targeting-row">
      <div class="targeting-form-id"><code>${escHtml(id)}</code>${variationId ? ` <span class="targeting-variant">var ${escHtml(String(variationId))}</span>` : ""}</div>
      <div class="targeting-details">
        ${variationId ? `Last shown: variation <strong>${escHtml(String(variationId))}</strong>` : "Shown (variation unknown)"}
        ${isSuppressed
          ? ` · <span class="targeting-suppressed">⛔ Closed ${escHtml(fmtDate(lastCloseTs) || "recently")}</span> — suppressed until form frequency resets`
          : " · <span class='targeting-ok'>Not suppressed</span>"}
      </div>
    </div>`;
  });

  return `<div class="section-block targeting-block">
    <div class="section-block-header info">
      <span class="section-icon">📋</span>
      <div>
        <div class="section-title">Form Targeting State</div>
        <div class="section-sub">What this browser's localStorage shows about form history</div>
      </div>
    </div>
    ${rows}
  </div>`;
}

// ── COPY DIAGNOSTIC REPORT ───────────────────────────────
document.addEventListener("click", async (e) => {
  if (!e.target.closest("#btn-copy-report")) return;
  const stored = await chrome.storage.local.get(["klvLastScan", "klvHistory", "klvHarHistory"]);
  const data   = stored?.klvLastScan?.data;
  if (!data) return;

  const lines = [];
  const domain = (() => { try { return new URL(data.url).hostname; } catch(_) { return data.url; } })();
  lines.push(`=== Klaviyo CSS Conflict Inspector Report ===`);
  lines.push(`Site: ${data.url}`);
  lines.push(`Scanned: ${new Date().toLocaleString()}`);
  lines.push(``);

  // Geo
  if (data.geoData) {
    const c = data.geoData.country_name || data.geoData.country || "";
    if (c) lines.push(`Location: ${c}`);
  }

  // CMP
  const cmps = data.cmp?.detected || [];
  if (cmps.length) lines.push(`Consent Platform: ${cmps.join(", ")}`);

  // Script health
  lines.push(`\n--- Script Health ---`);
  const scripts = data.scriptHealth?.scripts || [];
  if (scripts.length) lines.push(`Klaviyo script: ${scripts[0]?.src || "unknown"}`);
  const sIssues = data.scriptHealth?.issues || [];
  if (sIssues.length) {
    sIssues.forEach(i => lines.push(`[${i.severity.toUpperCase()}] ${i.title}: ${i.detail}`));
  } else {
    lines.push(`No script issues detected.`);
  }

  // CSP
  const cspIssues = data.csp?.issues || [];
  if (cspIssues.length) {
    lines.push(`\n--- Content Security Policy ---`);
    cspIssues.forEach(i => lines.push(`[${i.severity.toUpperCase()}] ${i.title}: ${i.detail}`));
  }

  // Form targeting
  const modal = data.formTargeting?.viewedForms?.modal;
  if (modal) {
    lines.push(`\n--- Form Targeting State ---`);
    const viewed   = modal.viewedForms   || {};
    const disabled = modal.disabledForms || {};
    Object.keys({ ...viewed, ...disabled }).forEach(id => {
      const varId    = viewed[id];
      const closeTs  = disabled[id]?.lastCloseTime;
      const closeStr = closeTs ? ` | Closed: ${new Date(closeTs < 1e10 ? closeTs * 1000 : closeTs).toLocaleString()}` : "";
      lines.push(`Form ${id}: variation ${varId || "unknown"}${closeStr}${closeTs ? " (suppressed)" : ""}`);
    });
  }

  // CSS form issues
  lines.push(`\n--- Forms (${data.formsFound} found) ---`);
  if (data.formsFound === 0) {
    lines.push(`No Klaviyo components found on page.`);
  } else {
    (data.forms || []).forEach(f => {
      lines.push(`\n${f.componentType || f.type || "Component"} — ${f.totalIssues} issue(s):`);
      const allIss = [
        ...(f.containerIssues || []).map(i => ({ ...i, _where: "container" })),
        ...(f.buttonResults  || []).flatMap(b => b.issues.map(i => ({ ...i, _where: b.element }))),
        ...(f.inputResults   || []).flatMap(r => r.issues.map(i => ({ ...i, _where: r.element }))),
      ];
      if (allIss.length === 0) lines.push(`  ✓ No CSS issues`);
      allIss.forEach(i => {
        const src = i.sources?.[0];
        const rule = src ? `${src.selector} { ${i.property}: ${src.value}${src.important ? " !important" : ""}; }` : i.property;
        lines.push(`  [${i.severity.toUpperCase()}] ${i.label} on ${i._where || "element"}: ${rule}${src ? ` (${src.source})` : ""}`);
      });
    });
  }

  // Scan History
  const scanHistory = stored.klvHistory || [];
  if (scanHistory.length) {
    lines.push(`\n--- Scan History (last ${scanHistory.length}) ---`);
    scanHistory.forEach((e, i) => {
      const ts  = e.ts ? new Date(e.ts).toLocaleString() : "unknown";
      const iss = e.totalIssues === 1 ? "1 issue" : `${e.totalIssues || 0} issues`;
      lines.push(`${i + 1}. ${e.domain || e.url} — ${ts} — ${iss}`);
    });
  }

  // HAR Captures
  const harHistory = stored.klvHarHistory || [];
  if (harHistory.length) {
    lines.push(`\n--- HAR Captures (last ${harHistory.length}) ---`);
    harHistory.forEach((e, i) => {
      const ts  = e.ts ? new Date(e.ts).toLocaleString() : "unknown";
      const req = e.entryCount === 1 ? "1 request" : `${e.entryCount || 0} requests`;
      const site = (() => { try { return new URL(e.url).hostname; } catch(_) { return e.url || "unknown"; } })();
      lines.push(`${i + 1}. ${site} — ${ts} — ${req}`);
    });
  }

  const report = lines.join("\n");
  try {
    await navigator.clipboard.writeText(report);
    const btn = document.getElementById("btn-copy-report");
    if (btn) { btn.textContent = "✓ Copied!"; setTimeout(() => { btn.textContent = "📋 Copy Report"; }, 2000); }
  } catch(_) {}
});

// ── EXPORT SCAN RESULTS AS JSON ──────────────────────────
// Downloads a .csv file containing the full scan data so an agent can
// share results with a developer or attach to a Zendesk ticket.
document.addEventListener("click", async (e) => {
  if (!e.target.closest("#btn-export-json")) return;
  const stored = await chrome.storage.local.get("klvLastScan");
  const scan   = stored?.klvLastScan;
  if (!scan) return;

  const data = scan.data;

  // CSV helper — wraps a value in quotes and escapes any internal quotes
  const csvCell = (v) => {
    const s = v == null ? "" : String(v);
    return `"${s.replace(/"/g, '""')}"`;
  };
  const csvRow = (...cells) => cells.map(csvCell).join(",");

  const headers = [
    "Scanned URL", "Scanned At", "Component Type", "Component ID",
    "Severity", "Issue", "Impact", "Element Path",
    "CSS Property", "Conflicting Rule", "Source File", "Suggested Fix"
  ];

  const rows = [headers.join(",")];

  const scannedAt = scan.ts ? new Date(scan.ts).toISOString() : "";
  const siteUrl   = scan.url || "";

  (data.forms || []).forEach(form => {
    const compType = form.componentType || form.type || "";
    const compId   = form.formId || "";

    const allIssues = [
      ...(form.containerIssues || []),
      ...(form.buttonResults  || []).flatMap(b => b.issues || []),
      ...(form.inputResults   || []).flatMap(r => r.issues || []),
    ];

    if (allIssues.length === 0) {
      rows.push(csvRow(siteUrl, scannedAt, compType, compId,
        "ok", "No issues", "", "", "", "", "", ""));
      return;
    }

    allIssues.forEach(issue => {
      const src       = (issue.sources || []).find(s => !s.crossOrigin) || (issue.sources || [])[0];
      const cssRule   = src
        ? `${src.selector || ""} { ${issue.property || ""}: ${src.value || ""}${src.important ? " !important" : ""}; }`
        : "";
      const srcFile   = src ? (src.source || "") : "";
      const fixAdvice = (() => {
        if (!issue.property) return "";
        const adv = typeof FIX_ADVICE !== "undefined" ? FIX_ADVICE[issue.property] : null;
        return adv ? adv.what || "" : "";
      })();

      rows.push(csvRow(
        siteUrl, scannedAt, compType, compId,
        issue.severity || "",
        issue.label || "",
        issue.explain || "",
        issue.domPath || "",
        issue.property || "",
        cssRule,
        srcFile,
        fixAdvice
      ));
    });
  });

  const csv  = rows.join("\r\n");
  const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
  const url  = URL.createObjectURL(blob);
  const domain = (() => { try { return new URL(scan.url).hostname.replace(/\./g, "_"); } catch(_) { return "scan"; } })();
  const filename = `klaviyo_scan_${domain}_${new Date().toISOString().replace(/[:.]/g, "-").slice(0, 19)}.csv`;

  const a  = document.createElement("a");
  a.href   = url;
  a.download = filename;
  a.style.display = "none";
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  setTimeout(() => URL.revokeObjectURL(url), 5000);

  const btn = document.getElementById("btn-export-json");
  if (btn) { btn.textContent = "✓ Exported!"; setTimeout(() => { btn.textContent = "⬇ Export"; }, 2000); }
});

// ── COPY DOM PATH ─────────────────────────────────────────
// Handles the ⧉ Copy button inside each .dom-breadcrumb row.
document.addEventListener("click", (e) => {
  const copyBtn = e.target.closest(".btn-copy-path");
  if (!copyBtn) return;
  const path = copyBtn.dataset.copy || "";
  navigator.clipboard.writeText(path).then(() => {
    const orig = copyBtn.textContent;
    copyBtn.textContent = "✓ Copied!";
    setTimeout(() => { copyBtn.textContent = orig; }, 2000);
  }).catch(() => {});
});

// ── TEST PROFILE MANAGEMENT (multi-profile) ───────────────
// Storage: klvTestEmails = [{ email, label? }], klvActiveEmail = email string
//          klvTestPhones = [{ phone, label? }], klvActivePhone = phone string

async function getTestProfile() {
  const stored = await chrome.storage.local.get(["klvActiveEmail", "klvActivePhone", "klvTestEmails", "klvTestPhones", "klvTestFirstName", "klvTestLastName", "klvTestDob"]);
  // Fallback: if no active selected, pick first in list
  const emails = stored.klvTestEmails || [];
  const phones = stored.klvTestPhones || [];
  const email  = stored.klvActiveEmail || emails[0]?.email || "";
  const phone  = stored.klvActivePhone || phones[0]?.phone || "";
  const phoneObj = phones.find(p => p.phone === phone) || phones[0] || null;
  const countryName = phoneObj?.countryName || "";
  // Name defaults to "Klaviyo Test" — overridable in Settings
  const firstName = stored.klvTestFirstName !== undefined ? stored.klvTestFirstName : "Klaviyo";
  const lastName  = stored.klvTestLastName  !== undefined ? stored.klvTestLastName  : "Test";
  // DOB defaults to 01/01/2000 (MM/DD/YYYY)
  const dob = stored.klvTestDob !== undefined ? stored.klvTestDob : "01/01/2000";
  return { email, phone, countryName, firstName, lastName, dob };
}

// Legacy save used in the prompt flow below — adds to list if not present,
// and marks as active.
async function saveTestProfile({ email, phone }) {
  const stored = await chrome.storage.local.get(["klvTestEmails", "klvTestPhones"]);
  const update = {};
  if (email !== undefined) {
    const emails = stored.klvTestEmails || [];
    if (!emails.find(e => e.email === email)) emails.push({ email });
    update.klvTestEmails  = emails;
    update.klvActiveEmail = email;
  }
  if (phone !== undefined) {
    const phones = stored.klvTestPhones || [];
    if (!phones.find(p => p.phone === phone)) phones.push({ phone });
    update.klvTestPhones  = phones;
    update.klvActivePhone = phone;
  }
  await chrome.storage.local.set(update);
}

// Renders the saved test profile chip in the Manual Check result area
async function renderTestProfileChip(container) {
  const { email, phone, firstName, lastName } = await getTestProfile();
  const emailStr = email || "—";
  const phoneStr = phone || "—";
  const nameStr  = [firstName, lastName].filter(Boolean).join(" ") || "Klaviyo Test";
  const existing = container.querySelector(".test-profile-chip");
  const html = `<div class="test-profile-chip">
    <span class="tpc-label">Test profile</span>
    <span class="tpc-field">👤 <span class="tpc-val">${escHtml(nameStr)}</span> <button class="tpc-edit" data-field="name" title="Change test name in Settings">✎</button></span>
    <span class="tpc-field">✉ <span class="tpc-val">${escHtml(emailStr)}</span> <button class="tpc-edit" data-field="email" title="Change test email — or manage emails in Settings">✎</button></span>
    <span class="tpc-field">📱 <span class="tpc-val">${escHtml(phoneStr)}</span> <button class="tpc-edit" data-field="phone" title="Change test phone — or manage phones in Settings">✎</button></span>
  </div>`;
  if (existing) {
    existing.outerHTML = html;
  } else {
    container.insertAdjacentHTML("beforeend", html);
  }
}

// ── SETTINGS PANEL ────────────────────────────────────────

async function renderSettingsLists() {
  const stored = await chrome.storage.local.get(["klvTestEmails", "klvTestPhones", "klvActiveEmail", "klvActivePhone", "klvTestFirstName", "klvTestLastName", "klvTestDob"]);
  const emails  = stored.klvTestEmails  || [];
  const phones  = stored.klvTestPhones  || [];
  const activeEmail = stored.klvActiveEmail || emails[0]?.email || "";
  const activePhone = stored.klvActivePhone || phones[0]?.phone || "";

  // Render email list
  const emailsListEl = document.getElementById("settings-emails-list");
  if (emailsListEl) {
    if (emails.length === 0) {
      emailsListEl.innerHTML = `<div class="settings-empty">No test emails saved yet.</div>`;
    } else {
      emailsListEl.innerHTML = emails.map((e, idx) => {
        const isActive = e.email === activeEmail;
        return `<div class="settings-item ${isActive ? "settings-item-active" : ""}" data-type="email" data-idx="${idx}">
          <button class="settings-select-btn" data-type="email" data-val="${escHtml(e.email)}" title="${isActive ? "Currently active" : "Set as active test email"}">${isActive ? "✔" : "○"}</button>
          <span class="settings-item-val">${escHtml(e.email)}</span>
          ${isActive ? `<span class="settings-active-badge">active</span>` : ""}
          <button class="settings-remove-btn" data-type="email" data-val="${escHtml(e.email)}" title="Remove">✕</button>
        </div>`;
      }).join("");
    }
  }

  // Render phone list
  const phonesListEl = document.getElementById("settings-phones-list");
  if (phonesListEl) {
    if (phones.length === 0) {
      phonesListEl.innerHTML = `<div class="settings-empty">No test phones saved yet.</div>`;
    } else {
      phonesListEl.innerHTML = phones.map((p, idx) => {
        const isActive = p.phone === activePhone;
        const countryLabel = p.countryName ? `<span class="settings-item-country">${escHtml(p.countryName)}</span>` : "";
        return `<div class="settings-item ${isActive ? "settings-item-active" : ""}" data-type="phone" data-idx="${idx}">
          <button class="settings-select-btn" data-type="phone" data-val="${escHtml(p.phone)}" title="${isActive ? "Currently active" : "Set as active test phone"}">${isActive ? "✔" : "○"}</button>
          <span class="settings-item-val">${escHtml(p.phone)}${countryLabel}</span>
          ${isActive ? `<span class="settings-active-badge">active</span>` : ""}
          <button class="settings-remove-btn" data-type="phone" data-val="${escHtml(p.phone)}" title="Remove">✕</button>
        </div>`;
      }).join("");
    }
  }

  // Populate name inputs
  const firstNameInput = document.getElementById("settings-first-name");
  const lastNameInput  = document.getElementById("settings-last-name");
  if (firstNameInput) firstNameInput.value = stored.klvTestFirstName !== undefined ? stored.klvTestFirstName : "Klaviyo";
  if (lastNameInput)  lastNameInput.value  = stored.klvTestLastName  !== undefined ? stored.klvTestLastName  : "Test";

  // Populate DOB input
  const dobInput = document.getElementById("settings-dob");
  if (dobInput) dobInput.value = stored.klvTestDob !== undefined ? stored.klvTestDob : "01/01/2000";

  attachSettingsListeners();
}

function attachSettingsListeners() {
  // Select (set active)
  document.querySelectorAll(".settings-select-btn").forEach(btn => {
    btn.addEventListener("click", async () => {
      const type = btn.dataset.type;
      const val  = btn.dataset.val;
      if (type === "email") await chrome.storage.local.set({ klvActiveEmail: val });
      if (type === "phone") await chrome.storage.local.set({ klvActivePhone: val });
      await renderSettingsLists();
    });
  });

  // Remove
  document.querySelectorAll(".settings-remove-btn").forEach(btn => {
    btn.addEventListener("click", async () => {
      const type = btn.dataset.type;
      const val  = btn.dataset.val;
      const stored = await chrome.storage.local.get(["klvTestEmails", "klvTestPhones", "klvActiveEmail", "klvActivePhone"]);
      const update = {};
      if (type === "email") {
        const emails = (stored.klvTestEmails || []).filter(e => e.email !== val);
        update.klvTestEmails = emails;
        if (stored.klvActiveEmail === val) update.klvActiveEmail = emails[0]?.email || "";
      }
      if (type === "phone") {
        const phones = (stored.klvTestPhones || []).filter(p => p.phone !== val);
        update.klvTestPhones = phones;
        if (stored.klvActivePhone === val) update.klvActivePhone = phones[0]?.phone || "";
      }
      await chrome.storage.local.set(update);
      await renderSettingsLists();
    });
  });

  // Name inputs — save on change (blur)
  const fnInput  = document.getElementById("settings-first-name");
  const lnInput  = document.getElementById("settings-last-name");
  const dobInput = document.getElementById("settings-dob");
  if (fnInput) {
    fnInput.addEventListener("change", () => {
      chrome.storage.local.set({ klvTestFirstName: fnInput.value.trim() });
    });
  }
  if (lnInput) {
    lnInput.addEventListener("change", () => {
      chrome.storage.local.set({ klvTestLastName: lnInput.value.trim() });
    });
  }
  if (dobInput) {
    dobInput.addEventListener("change", () => {
      chrome.storage.local.set({ klvTestDob: dobInput.value.trim() });
    });
  }
}

// Add email button
document.getElementById("settings-add-email-btn").addEventListener("click", async () => {
  const val = (document.getElementById("settings-new-email")?.value || "").trim();
  if (!val || !val.includes("@")) {
    showSettingsError("emails", "Enter a valid email address.");
    return;
  }
  const stored = await chrome.storage.local.get(["klvTestEmails", "klvActiveEmail"]);
  const emails = stored.klvTestEmails || [];
  if (emails.find(e => e.email === val)) {
    showSettingsError("emails", "Already saved.");
    return;
  }
  emails.push({ email: val });
  const update = { klvTestEmails: emails };
  if (!stored.klvActiveEmail) update.klvActiveEmail = val;
  await chrome.storage.local.set(update);
  document.getElementById("settings-new-email").value = "";
  await renderSettingsLists();
});

